import java.lang.ProcessBuilder;
import java.lang.Process;

// Close all applications at once
public class CloseAllApplications {
    public static void main(String[] args) {
        ProcessBuilder processBuilder = new ProcessBuilder();
        processBuilder.command("taskkill", "/im", "*");
        processBuilder.start();
    }
}

// Close applications in batches
public class CloseApplicationsInBatches {
    public static void main(String[] args) {
        ProcessBuilder processBuilder = new ProcessBuilder();
        processBuilder.command("taskkill", "/im", "chrome.exe");
        processBuilder.start();
    }
}

// Close applications by type
public class CloseApplicationsByType {
    public static void main(String[] args) {
        ProcessBuilder processBuilder = new ProcessBuilder();
        processBuilder.command("taskkill", "/im", "chrome.exe");
        processBuilder.start();
    }
}
